import{_ as t,o as n,c as r,ag as a}from"./chunks/framework.B9unkguw.js";const d=JSON.parse('{"title":"设置视图","description":"","frontmatter":{},"headers":[],"relativePath":"zh/qgc-user-guide/settings_view/settings_view.md","filePath":"zh/qgc-user-guide/settings_view/settings_view.md"}'),o={name:"zh/qgc-user-guide/settings_view/settings_view.md"};function s(i,e,g,l,h,p){return n(),r("div",null,e[0]||(e[0]=[a('<h1 id="设置视图" tabindex="-1">设置视图 <a class="header-anchor" href="#设置视图" aria-label="Permalink to &quot;设置视图&quot;">​</a></h1><p><em>设置视图</em> 用于配置 <em>QGroundControl</em> 应用程序 (而不是特定的载具) 的设置。 您无需连接载具就能更改这些值。</p><p>You can switch between the various settings pages by clicking the buttons in the left-sidebar.</p><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h2><p>Use the <strong>search bar</strong> at the top of the settings sidebar to find any setting by name. As you type, matching settings are shown across all pages — click a result to jump directly to that setting. This is the fastest way to find a setting when you don&#39;t know which page it&#39;s on.</p><h2 id="settings-pages" tabindex="-1">Settings Pages <a class="header-anchor" href="#settings-pages" aria-label="Permalink to &quot;Settings Pages&quot;">​</a></h2><p><strong><a href="./general.html">General</a></strong> <br>The main application configuration settings: display units, autoconnection devices, language, color scheme, and other core options.</p><p><strong><a href="./fly_view.html">Fly View</a></strong> <br>Configure Fly View behavior: preflight checklist, guided mode, virtual joystick, and instrument panel options.</p><p><strong><a href="./3d_view.html">3D View</a></strong> <br>Enable and configure the 3D map view.</p><p><strong><a href="./plan_view.html">Plan View</a></strong> <br>Configure Plan View defaults: mission altitude, VTOL transition distance, and landing pattern options.</p><p><strong><a href="./adsb_server.html">ADSB Server</a></strong> <br>Configure the ADS-B traffic tracking server connection for nearby aircraft display.</p><p><strong><a href="./comm_links.html">Comm Links</a></strong> <br>Manually create communication links and configure auto-connect options.</p><p><strong><a href="./console_logging.html">Logging</a></strong> <br>Capture application logs for help with diagnosing problems.</p><p><strong><a href="./maps.html">Maps</a></strong> <br>Map provider selection, offline tile management, API tokens, custom tile servers, and cache settings.</p><p><strong><a href="./ntrip_rtk.html">NTRIP / RTK</a></strong> <br>Configure the built-in NTRIP client for streaming RTK correction data to the vehicle.</p><p><strong><a href="./px4_log_transfer.html">PX4 Log Transfer</a></strong> <br>Configure PX4 log download and upload settings.</p><p><strong><a href="./remote_id.html">Remote ID</a></strong> <br>Configure drone Remote ID settings including registration, region, and operator information.</p><p><strong><a href="./telemetry.html">Telemetry</a></strong> <br>Settings associated with the MAVLink connection to a vehicle.</p><p><strong><a href="./video.html">Video</a></strong> <br>Configure video source, stream URL, recording options, and decoder settings.</p><p><strong><a href="./help.html">Help</a></strong> <br>Links to QGroundControl user guide, forums, and support resources.</p>',20)]))}const m=t(o,[["render",s]]);export{d as __pageData,m as default};
